# VERIFICATION
# ═══════════════════════════════════════════════════════════════

def wc(text):
    return len(text.split())

targets = {"easy": (450, 550), "medium": (1100, 1400), "hard": (2200, 2600)}
failures = []

for ch_num in [16, 17, 18]:
    cv = ch_map[ch_num]["contentVariants"]
    print(f"\n=== CH{ch_num} ===")
    for diff in ["easy", "medium", "hard"]:
        lo, hi = targets[diff]
        for tone, text in cv[diff]["chapterBreakdown"].items():
            w = wc(text)
            status = "PASS" if lo <= w <= hi else "FAIL"
            print(f"  {diff:6s} {tone:12s}: {w:5d} words  [{status}]")
            if status == "FAIL":
                failures.append(f"  ch{ch_num} {diff} {tone}: {w} words (target {lo}-{hi})")

if failures:
    print(f"\n!!! {len(failures)} FAILURES !!!")
    for f in failures:
        print(f)
else:
    print("\nALL WORD COUNTS PASS!")
